#!/usr/bin/env python3
"""Build the sommelier food catalogue as Parquet.

Run from repo root:
    python models/sommelier/build_catalogue.py

Produces models/sommelier/food_catalogue.parquet with ~1,600 curated dishes.
"""

from __future__ import annotations

import sys
from pathlib import Path

import pyarrow as pa
import pyarrow.parquet as pq

# Ensure cellarbrain package is importable when running standalone
_repo = Path(__file__).resolve().parent.parent.parent
if str(_repo / "src") not in sys.path:
    sys.path.insert(0, str(_repo / "src"))

from cellarbrain.sommelier.schemas import (
    COOKING_METHODS,
    FOOD_CATALOGUE_SCHEMA,
    PROTEINS,
    WEIGHT_CLASSES,
)

# ---------------------------------------------------------------------------
# Dish definitions — grouped by cuisine
# Each dish: (dish_id, dish_name, description, ingredients, cuisine,
#             weight_class, protein, cooking_method, flavour_profile)
# ---------------------------------------------------------------------------

_DISHES: list[tuple[str, str, str, list[str], str, str, str | None, str, list[str]]] = []


def _add(dish_id: str, dish_name: str, description: str,
         ingredients: list[str], cuisine: str, weight_class: str,
         protein: str | None, cooking_method: str,
         flavour_profile: list[str]) -> None:
    _DISHES.append((dish_id, dish_name, description, ingredients, cuisine,
                     weight_class, protein, cooking_method, flavour_profile))


