# ---------------------------------------------------------------------------
# Validation & Assembly
# ---------------------------------------------------------------------------


def validate_and_write(output_path: Path) -> None:
    """Validate all dishes and write to Parquet."""
    seen_ids: set[str] = set()
    errors: list[str] = []

    for i, (did, dname, desc, ings, cuisine, wc, prot, cm, fp) in enumerate(_DISHES):
        if did in seen_ids:
            errors.append(f"Duplicate dish_id: {did}")
        seen_ids.add(did)

        if wc not in WEIGHT_CLASSES:
            errors.append(f"{did}: invalid weight_class '{wc}'")
        if prot is not None and prot not in PROTEINS:
            errors.append(f"{did}: invalid protein '{prot}'")
        if cm not in COOKING_METHODS:
            errors.append(f"{did}: invalid cooking_method '{cm}'")
        if len(ings) < 1:
            errors.append(f"{did}: empty ingredients")
        if len(fp) < 1:
            errors.append(f"{did}: empty flavour_profile")
        if len(desc) < 10:
            errors.append(f"{did}: description too short ({len(desc)})")

    if errors:
        for e in errors:
            print(f"  ERROR: {e}", file=sys.stderr)
        raise ValueError(f"{len(errors)} validation errors")

    # Build Arrow table
    table = pa.table(
        {
            "dish_id": [d[0] for d in _DISHES],
            "dish_name": [d[1] for d in _DISHES],
            "description": [d[2] for d in _DISHES],
            "ingredients": [d[3] for d in _DISHES],
            "cuisine": [d[4] for d in _DISHES],
            "weight_class": [d[5] for d in _DISHES],
            "protein": [d[6] for d in _DISHES],
            "cooking_method": [d[7] for d in _DISHES],
            "flavour_profile": [d[8] for d in _DISHES],
        },
        schema=FOOD_CATALOGUE_SCHEMA,
    )

    output_path.parent.mkdir(parents=True, exist_ok=True)
    pq.write_table(table, output_path)

    # Summary
    cuisines: dict[str, int] = {}
    for d in _DISHES:
        cuisines[d[4]] = cuisines.get(d[4], 0) + 1

    print(f"Wrote {len(_DISHES)} dishes to {output_path}")
    print(f"Cuisines ({len(cuisines)}):")
    for c, n in sorted(cuisines.items(), key=lambda x: -x[1]):
        print(f"  {c}: {n}")


if __name__ == "__main__":
    out = Path(__file__).resolve().parent / "food_catalogue.parquet"
    validate_and_write(out)
